func isUUIDNamedType(t *ast.NamedType) bool {
	if t == nil || len(t.Path) != 1 {
		return false
	}
	return strings.EqualFold(pathNameFromIdentPath(t.Path), spannerUUIDTypeName)
}

func uuidGoType(nullable bool) goTypeInfo {
	if nullable {
		return goTypeInfo{
			Expr:            "spanner.NullUUID",
			BaseSpannerType: spannerUUIDTypeName,
		}
	}
	return goTypeInfo{
		Expr:            "uuid.UUID",
		BaseSpannerType: spannerUUIDTypeName,
		Imports:         []ImportSpec{{Path: "github.com/google/uuid"}},
	}
}

func refreshTypeMetadata(t *Type) {
	t.PrimaryKeyFields = refreshOrderedFields(t.Fields, t.PrimaryKeyFields, func(field Field) bool {
		return field.IsPrimaryKey
	})
	t.CommitTSFields = t.CommitTSFields[:0]

	imports := []ImportSpec{
		{Path: "context"},
		{Path: "fmt"},
		{Path: "cloud.google.com/go/spanner"},
	}
