func (g *Generator) writeTemplate(filename, templateName string, data any) error {
	funcMap := template.FuncMap{
		"lowerFirst": lowerCamel,
		"commitTimestampExpr": func(field Field) string {
			expr, _ := commitTimestampExpr(field)
			return expr
		},
	}

