	if err != nil {
		return fmt.Errorf("reading template %s: %w", templateName, err)
	}
	headerText, err := fs.ReadFile(g.templateFS, headerTemplateName)
	if err != nil {
		return fmt.Errorf("reading template %s: %w", headerTemplateName, err)
	}

	tmpl, err := template.New(templateName).Funcs(funcMap).Parse(string(headerText) + "\n" + string(tmplText))
	if err != nil {
		return fmt.Errorf("parsing template %s: %w", templateName, err)
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return fmt.Errorf("executing template: %w", err)
	}

	// Format Go code.
	if g.opts.Language == "go" {
		formatted := g.formatGoSource(buf.Bytes())
		buf.Reset()
		buf.Write(formatted)
	}

	path := filepath.Join(g.opts.OutDir, filename)
	if err := os.WriteFile(path, buf.Bytes(), 0o644); err != nil {
		return fmt.Errorf("writing file %s: %w", path, err)
	}

	return nil
}

func (g *Generator) formatGoSource(src []byte) []byte {
	modulePath, langVersion := detectGoModuleConfig(g.opts.OutDir)
